from __future__ import annotations

from pathlib import Path
import shutil
import datetime

ROOT = Path(__file__).resolve().parent
MANAGER = ROOT / "core_v10" / "extension_manager.py"
FLEET = ROOT / "core_v10" / "fleet_registry.py"

EXTENSION_MANAGER_PY = 'from __future__ import annotations\n\nimport importlib.util\nimport sys\nfrom dataclasses import dataclass, field\nfrom pathlib import Path\nfrom typing import Any\n\nimport pluggy\n\nfrom .extension_context import ExtensionContext\nfrom .extension_hooks import FoxAIExtensionSpec\nfrom .extension_manifest import read_manifest\n\n\n@dataclass\nclass ExtensionManager:\n    foxai_root: Path\n    plugin_manager: pluggy.PluginManager = field(init=False)\n    context: ExtensionContext = field(init=False)\n    manifests: dict[str, dict[str, Any]] = field(default_factory=dict, init=False)\n\n    def __post_init__(self) -> None:\n        self.foxai_root = Path(self.foxai_root).resolve()\n        self.context = ExtensionContext(self.foxai_root)\n        self.context.ensure_roots()\n        self.plugin_manager = pluggy.PluginManager("foxai")\n        self.plugin_manager.add_hookspecs(FoxAIExtensionSpec)\n        self.discover_plugins()\n\n    @property\n    def extensions_root(self) -> Path:\n        return self.context.extensions\n\n    def discover_plugins(self) -> None:\n        self.manifests = {}\n\n        for manifest_path in sorted(self.extensions_root.rglob("extension.json")):\n            manifest = read_manifest(manifest_path)\n            manifest["_manifest_path"] = str(manifest_path)\n            manifest["_extension_dir"] = str(manifest_path.parent)\n            self.manifests[manifest["key"]] = manifest\n\n        for plugin_path in sorted(self.extensions_root.rglob("plugin.py")):\n            name = "foxai_ext_" + "_".join(plugin_path.relative_to(self.extensions_root).parts[:-1])\n            name = "".join(c if c.isalnum() or c == "_" else "_" for c in name)\n            if self.plugin_manager.has_plugin(name):\n                continue\n            try:\n                spec = importlib.util.spec_from_file_location(name, plugin_path)\n                if not spec or not spec.loader:\n                    continue\n                module = importlib.util.module_from_spec(spec)\n                sys.modules[name] = module\n                spec.loader.exec_module(module)\n                self.plugin_manager.register(module, name=name)\n            except Exception as exc:\n                print(f"[ExtensionManager] Failed to load {plugin_path}: {exc}")\n\n    def _runtime_metadata(self, manifest: dict[str, Any]) -> dict[str, Any]:\n        exe = self.context.find_manifest_executable(manifest)\n        out = dict(manifest)\n        out["installed"] = bool(exe) if not manifest.get("reserved") else False\n        out["path"] = str(exe) if exe else manifest.get("path")\n        out["shuttle_record"] = {\n            "callsign": out.get("callsign") or out.get("name"),\n            "department": out.get("department"),\n            "health": "reserved" if out.get("reserved") else ("installed" if exe else "missing"),\n            "capabilities": out.get("capabilities", []),\n        }\n        return out\n\n    def list_extensions(self) -> list[dict[str, Any]]:\n        self.discover_plugins()\n        items = [self._runtime_metadata(m) for m in self.manifests.values()]\n        return sorted(items, key=lambda x: (x.get("department", ""), int(x.get("priority", 50)), x.get("name", "")))\n\n    def executable_inventory(self) -> list[dict[str, Any]]:\n        return self.context.executable_inventory()\n\n    def passive_health(self, key: str | None = None) -> dict[str, Any]:\n        # Safe default: no plugin hooks, no subprocesses, no GUI launches.\n        self.discover_plugins()\n        extensions = self.list_extensions()\n        target = [x for x in extensions if (not key or x.get("key") == key)]\n\n        if key and not target:\n            return {"ok": False, "message": f"Unknown extension: {key}"}\n\n        def one(ext: dict[str, Any]) -> dict[str, Any]:\n            if ext.get("reserved"):\n                return {\n                    "key": ext.get("key"),\n                    "ok": False,\n                    "status": "reserved",\n                    "message": f"{ext.get(\'name\')} is reserved.",\n                    "path": ext.get("path"),\n                }\n\n            if ext.get("installed"):\n                return {\n                    "key": ext.get("key"),\n                    "ok": True,\n                    "status": "ready",\n                    "message": f"{ext.get(\'name\')} found.",\n                    "path": ext.get("path"),\n                }\n\n            return {\n                "key": ext.get("key"),\n                "ok": False,\n                "status": "missing",\n                "message": f"No matching executable found for {ext.get(\'executables\', [])}.",\n                "path": ext.get("path"),\n            }\n\n        if key:\n            return one(target[0])\n\n        return {\n            "ok": True,\n            "mode": "passive",\n            "total": len(extensions),\n            "items": [{**ext, "health": one(ext)} for ext in extensions],\n        }\n\n    def diagnostic_health(self, key: str | None = None) -> dict[str, Any]:\n        # Explicit diagnostic mode may call plugin health hooks.\n        self.discover_plugins()\n        extensions = self.list_extensions()\n        target = [x for x in extensions if (not key or x.get("key") == key)]\n\n        if key and not target:\n            return {"ok": False, "message": f"Unknown extension: {key}"}\n\n        health_by_key: dict[str, dict[str, Any]] = {}\n        for manifest in target:\n            results = self.plugin_manager.hook.extension_health(context=self.context, manifest=manifest)\n            chosen = None\n            for result in results:\n                if isinstance(result, dict) and result.get("key") == manifest.get("key"):\n                    chosen = result\n                    break\n            if not chosen:\n                chosen = self.passive_health(manifest.get("key"))\n            health_by_key[manifest["key"]] = chosen\n\n        if key:\n            return health_by_key[key]\n\n        return {\n            "ok": True,\n            "mode": "diagnostic",\n            "total": len(extensions),\n            "items": [{**ext, "health": health_by_key.get(ext["key"])} for ext in extensions],\n        }\n\n    def health(self, key: str | None = None) -> dict[str, Any]:\n        return self.passive_health(key)\n\n    def find_capability(self, capability: str) -> list[dict[str, Any]]:\n        cap = capability.lower().strip()\n        return [\n            ext for ext in self.list_extensions()\n            if cap in [str(c).lower() for c in ext.get("capabilities", [])]\n        ]\n\n    def launch(self, key: str) -> dict[str, Any]:\n        manifest = self.manifests.get(key)\n        if not manifest:\n            self.discover_plugins()\n            manifest = self.manifests.get(key)\n        if not manifest:\n            return {"ok": False, "key": key, "message": f"Unknown extension: {key}"}\n\n        results = self.plugin_manager.hook.extension_launch(context=self.context, manifest=manifest, key=key)\n        for result in results:\n            if isinstance(result, dict) and result.get("key") == key:\n                return result\n\n        return {"ok": False, "key": key, "message": f"No launch handler responded for extension: {key}"}\n\n    def invoke(self, key: str, action: str, payload: dict | None = None) -> dict[str, Any]:\n        manifest = self.manifests.get(key)\n        if not manifest:\n            self.discover_plugins()\n            manifest = self.manifests.get(key)\n        if not manifest:\n            return {"ok": False, "key": key, "message": f"Unknown extension: {key}"}\n\n        results = self.plugin_manager.hook.extension_invoke(context=self.context, manifest=manifest, key=key, action=action, payload=payload or {})\n        for result in results:\n            if isinstance(result, dict) and result.get("key") == key:\n                return result\n\n        return {"ok": False, "key": key, "message": f"No invoke handler responded for extension: {key}.{action}"}\n'
FLEET_REGISTRY_PY = 'from __future__ import annotations\n\nimport json\nfrom dataclasses import dataclass\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Any\n\nfrom .extension_commissioner import commission_known_extensions\nfrom .extension_manager import ExtensionManager\n\n\ndef now() -> str:\n    return datetime.now().isoformat(timespec="seconds")\n\n\n@dataclass\nclass FleetRegistry:\n    foxai_root: Path\n\n    @property\n    def registry_path(self) -> Path:\n        path = Path(self.foxai_root) / "Config" / "fleet_registry.json"\n        path.parent.mkdir(parents=True, exist_ok=True)\n        return path\n\n    def load(self) -> dict[str, Any]:\n        if not self.registry_path.exists():\n            return {"schema": 1, "updated": None, "mode": "passive", "shuttles": {}}\n        try:\n            data = json.loads(self.registry_path.read_text(encoding="utf-8"))\n            if isinstance(data, dict):\n                data.setdefault("schema", 1)\n                data.setdefault("updated", None)\n                data.setdefault("mode", "passive")\n                data.setdefault("shuttles", {})\n                return data\n        except Exception:\n            pass\n        return {"schema": 1, "updated": None, "mode": "passive", "shuttles": {}}\n\n    def save(self, data: dict[str, Any]) -> None:\n        data["updated"] = now()\n        self.registry_path.write_text(json.dumps(data, indent=2), encoding="utf-8")\n\n    def refresh(self) -> dict[str, Any]:\n        # Safe refresh: passive health only. No plugin hooks, no app launches.\n        manager = ExtensionManager(Path(self.foxai_root))\n        health = manager.passive_health()\n        old = self.load()\n        old_shuttles = old.get("shuttles", {})\n        shuttles: dict[str, Any] = {}\n\n        for item in health.get("items", []):\n            key = item.get("key")\n            h = item.get("health") or {}\n            prior = old_shuttles.get(key, {})\n\n            status = h.get("status", "unknown")\n            if item.get("reserved"):\n                service_state = "Reserved"\n            elif status in ("ready", "installed", "online"):\n                service_state = "Operational"\n            elif status == "missing":\n                service_state = "Missing"\n            elif status == "offline":\n                service_state = "Docked"\n            else:\n                service_state = "Unknown"\n\n            shuttles[key] = {\n                "key": key,\n                "name": item.get("name"),\n                "callsign": item.get("callsign") or item.get("name"),\n                "department": item.get("department", "General"),\n                "category": item.get("category", "Utility"),\n                "service_state": service_state,\n                "installed": bool(item.get("installed")),\n                "reserved": bool(item.get("reserved")),\n                "health_status": status,\n                "health_message": h.get("message"),\n                "health_mode": "passive",\n                "path": h.get("path") or item.get("path"),\n                "capabilities": item.get("capabilities", []),\n                "last_seen": now(),\n                "last_used": prior.get("last_used"),\n                "launches": prior.get("launches", 0),\n                "manifest_path": item.get("_manifest_path"),\n            }\n\n        data = {"schema": 1, "updated": now(), "mode": "passive", "shuttles": shuttles}\n        self.save(data)\n        return data\n\n    def scan_and_commission(self) -> dict[str, Any]:\n        commission = commission_known_extensions(Path(self.foxai_root), overwrite=False)\n        registry = self.refresh()\n        return {\n            "ok": True,\n            "commission": commission,\n            "registry": registry,\n            "summary": self.summary(registry),\n        }\n\n    def summary(self, data: dict[str, Any] | None = None) -> dict[str, Any]:\n        data = data or self.load()\n        shuttles = list((data.get("shuttles") or {}).values())\n        departments: dict[str, list[dict[str, Any]]] = {}\n\n        for shuttle in shuttles:\n            departments.setdefault(shuttle.get("department", "General"), []).append(shuttle)\n\n        for dept in departments:\n            departments[dept] = sorted(departments[dept], key=lambda x: x.get("callsign", ""))\n\n        states: dict[str, int] = {}\n        for shuttle in shuttles:\n            state = shuttle.get("service_state", "Unknown")\n            states[state] = states.get(state, 0) + 1\n\n        return {\n            "ok": True,\n            "updated": data.get("updated"),\n            "mode": data.get("mode", "passive"),\n            "total": len(shuttles),\n            "states": states,\n            "departments": departments,\n        }\n\n    def mark_used(self, key: str) -> dict[str, Any]:\n        data = self.load()\n        shuttles = data.setdefault("shuttles", {})\n        if key not in shuttles:\n            return {"ok": False, "message": f"Unknown shuttle pod: {key}"}\n        shuttles[key]["last_used"] = now()\n        shuttles[key]["launches"] = int(shuttles[key].get("launches", 0)) + 1\n        self.save(data)\n        return {"ok": True, "shuttle": shuttles[key]}\n'


def backup(path: Path) -> Path:
    stamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    out = path.with_name(f"{path.stem}_backup_before_lifecycle_guard_{stamp}{path.suffix}")
    shutil.copy2(path, out)
    return out


def fail(msg: str) -> None:
    print("[CM v2.3b ERROR]", msg)
    raise SystemExit(1)


def main() -> int:
    if not MANAGER.exists():
        fail("core_v10\\extension_manager.py not found.")
    if not FLEET.exists():
        fail("core_v10\\fleet_registry.py not found.")

    print("FOXAI CM v2.3b No-Launch Lifecycle Guard")
    print("========================================")
    print()

    b1 = backup(MANAGER)
    b2 = backup(FLEET)

    MANAGER.write_text(EXTENSION_MANAGER_PY, encoding="utf-8")
    FLEET.write_text(FLEET_REGISTRY_PY, encoding="utf-8")

    print(f"Patched: {MANAGER}")
    print(f"Backup:  {b1}")
    print()
    print(f"Patched: {FLEET}")
    print(f"Backup:  {b2}")
    print()
    print("Now run TEST_NO_LAUNCH_LIFECYCLE_GUARD.bat, then TEST_FLEET_REGISTRY.bat.")
    print("Expected: no GUI apps or command-help windows open.")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
